SET NAMES utf8mb4;

CREATE TABLE IF NOT EXISTS `asda2bbquestrecord` (
  `QuestName` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `Id` int NOT NULL,
  `StartLevel` int NOT NULL,
  `EndLevel` int NOT NULL,
  `Exp` int NOT NULL,
  `Gold` int NOT NULL,
  `Monster1Id` int NOT NULL,
  `Monster1Amount` int NOT NULL,
  `Monster2Id` int NOT NULL,
  `Monster2Amount` int NOT NULL,
  `Monster3Id` int NOT NULL,
  `Monster3Amount` int NOT NULL,
  `Monster4Id` int NOT NULL,
  `Monster4Amount` int NOT NULL,
  `Monster5Id` int NOT NULL,
  `Monster5Amount` int NOT NULL,
  `Item1Id` int NOT NULL,
  `Item1Amount` int NOT NULL,
  `Item2Id` int NOT NULL,
  `Item2Amount` int NOT NULL,
  `Item3Id` int NOT NULL,
  `Item3Amount` int NOT NULL,
  `Item4Id` int NOT NULL,
  `Item4Amount` int NOT NULL,
  `Item5Id` int NOT NULL,
  `Item5Amount` int NOT NULL,
  `RepeatCount` int NOT NULL,
  `Reward1Id` int NOT NULL,
  `Reward1Amount` int NOT NULL,
  `Reward2Id` int NOT NULL,
  `Reward2Amount` int NOT NULL,
  `Item1ReqAmount` int NOT NULL,
  `Item2ReqAmount` int NOT NULL,
  `Item3ReqAmount` int NOT NULL,
  `Item4ReqAmount` int NOT NULL,
  `Item5ReqAmount` int NOT NULL,
  PRIMARY KEY (`Id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


